<template><header class="detail-header"><div><h2>{{ name }}</h2><p>{{ scenario }}</p></div><div class="detail-actions"><span v-if="loop != null" class="loop-pill">{{ loopLabel }}</span><el-tag :type="statusType" effect="light">{{ statusText }}</el-tag><el-button v-if="status === 'running'" type="danger" plain size="small" @click="$emit('stop')">停止</el-button></div></header></template>
<script setup lang="ts">import { computed } from 'vue'; import type { TraceStatus } from '../types'; const props = defineProps<{ name:string; scenario:string; status:TraceStatus; loop:number|null }>(); defineEmits<{stop:[]}>(); const statusText=computed(()=>({idle:'待查看',running:'运行中',done:'已完成',error:'异常'}[props.status])); const statusType=computed(()=>props.status==='done'?'success':props.status==='running'?'warning':props.status==='error'?'danger':'info');const numbers=['一','二','三','四','五','六','七','八','九','十'];const loopLabel=computed(()=>props.loop==null?'':`第${numbers[props.loop]||props.loop+1}轮`)</script>
